import{_ as t,o as a,c as i,ae as o}from"./chunks/framework.B6gjLfeO.js";const d=JSON.parse('{"title":"Configure SSO (General SAML)","description":"","frontmatter":{"title":"Configure SSO (General SAML)","slug":"configure-sso"},"headers":[],"relativePath":"account-hub/configure-sso.md","filePath":"account-hub/configure-sso.md"}'),n={name:"account-hub/configure-sso.md"};function s(r,e,l,c,u,p){return a(),i("div",null,[...e[0]||(e[0]=[o(`<h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Branch uses Auth0 to enable single sign-on (SSO), which allows you to manage your team&#39;s access to the Branch Dashboard through your identity provider (IdP).</p><p>Using SSO makes it easier to add or remove Branch users, and improves their login experience.</p><h2 id="configure-sso" tabindex="-1">Configure SSO <a class="header-anchor" href="#configure-sso" aria-label="Permalink to &quot;Configure SSO&quot;">​</a></h2><p>To configure SSO, you&#39;ll need to set up Branch in your IdP and enter your IdP information in the Branch Dashboard.</p><h3 id="before-you-begin" tabindex="-1">Before you begin <a class="header-anchor" href="#before-you-begin" aria-label="Permalink to &quot;Before you begin&quot;">​</a></h3><p>Before you begin, ensure you have:</p><ul><li><p>Admin access to your Branch account.</p></li><li><p>Admin access to your organization&#39;s IdP (e.g., Okta, Azure AD) account.</p></li><li><p>SSO enabled for your Branch account.</p><ul><li>Access to SSO requires a Branch plan. Please visit our <a href="https://www.branch.io/pricing/" target="_blank" rel="noreferrer">Pricing</a> page or <a href="https://branchdocs.app.link/e/sso-sign-up" target="_blank" rel="noreferrer">contact our Sales team</a> to learn more about pricing and availability.</li></ul></li></ul><div class="info custom-block"><p class="custom-block-title">Note</p><p>Please follow the steps below whether you’re setting up SSO for the first time or you’re an existing customer using Branch SSO and migrating.</p></div><h3 id="step-1-select-identity-provider" tabindex="-1">Step 1: Select identity provider <a class="header-anchor" href="#step-1-select-identity-provider" aria-label="Permalink to &quot;Step 1: Select identity provider&quot;">​</a></h3><p>This step is different depending on whether you are on the <a href="./branch-dashboard-overview.html">legacy</a> or <a href="./new-branch-overview.html">new</a> Branch experience. The rest of the steps remain the same between the two platforms.</p><h3 id="step-2-configure-custom-saml" tabindex="-1">Step 2: Configure custom SAML <a class="header-anchor" href="#step-2-configure-custom-saml" aria-label="Permalink to &quot;Step 2: Configure custom SAML&quot;">​</a></h3><h4 id="step-2-1-create-application" tabindex="-1">Step 2.1: Create application <a class="header-anchor" href="#step-2-1-create-application" aria-label="Permalink to &quot;Step 2.1: Create application&quot;">​</a></h4><ol><li><p>Copy the unique values that get populated for <strong>Single Sign-On URL</strong> and <strong>Service Provider Identity ID</strong> and use them to create a generic SAML application in your Identity Provider.</p><ol><li><p>Single Sign-On URL:</p><ol><li>Endpoint users are redirected to for initiating single sign-on, enabling users to access multiple applications.</li><li>Also known as: Assertion Consumer Service URL, Callback URL.</li></ol></li><li><p>Service Provider Entity ID:</p><ol><li>Unique identifier for service provider.</li><li>Also known as: Audience URI.</li></ol></li></ol><p>When creating the application in your IdP, you may also need to specify an <strong>Application URL (also called SP URL)</strong>. Use <a href="https://dashboard.branch.io" target="_blank" rel="noreferrer">https://dashboard.branch.io</a> for this field.</p><p>This is the URL where users will access Branch to log in.</p></li><li><p>Click <strong>Next</strong>.</p></li></ol><h4 id="step-2-2-map-attributes" tabindex="-1">Step 2.2: Map attributes <a class="header-anchor" href="#step-2-2-map-attributes" aria-label="Permalink to &quot;Step 2.2: Map attributes&quot;">​</a></h4><p>Set up attribute mapping to ensure user information syncs correctly between your identity provider and Branch.</p><div class="danger custom-block"><p class="custom-block-title">Warning</p><p>To set up a successful mapping, you must use the values listed here <strong>exactly as they are capitalized and spelled</strong> in this article.</p></div><p><strong>Required attributes</strong>:</p><p>Configure your IdP to send the following three attributes in the SAML response:</p><ul><li><code>email</code></li><li><code>firstName</code></li><li><code>lastName</code></li></ul><p><strong>Important configuration notes</strong>:</p><ul><li><p>Use simple string attribute names, as shown above.</p></li><li><p>Do <strong>not</strong> use URN or OID formats.</p></li><li><p>Including <code>NameFormat</code> for attributes is optional and can be omitted.</p><ul><li>If your IdP requires <code>NameFormat</code>, use the value <code>urn:oasis:names:tc:SAML:2.0:attrname-format:unspecified</code>.</li></ul></li></ul><p><strong>Example SAML AttributeStatement</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;AttributeStatement&gt;</span></span>
<span class="line"><span>  &lt;Attribute Name=&quot;email&quot;&gt;</span></span>
<span class="line"><span>    &lt;AttributeValue&gt;user@example.com&lt;/AttributeValue&gt;</span></span>
<span class="line"><span>  &lt;/Attribute&gt;</span></span>
<span class="line"><span>  &lt;Attribute Name=&quot;firstName&quot;&gt;</span></span>
<span class="line"><span>    &lt;AttributeValue&gt;John&lt;/AttributeValue&gt;</span></span>
<span class="line"><span>  &lt;/Attribute&gt;</span></span>
<span class="line"><span>  &lt;Attribute Name=&quot;lastName&quot;&gt;</span></span>
<span class="line"><span>    &lt;AttributeValue&gt;Doe&lt;/AttributeValue&gt;</span></span>
<span class="line"><span>  &lt;/Attribute&gt;</span></span>
<span class="line"><span>&lt;/AttributeStatement&gt;</span></span></code></pre></div><h4 id="step-2-3-configure-connection" tabindex="-1">Step 2.3: Configure connection <a class="header-anchor" href="#step-2-3-configure-connection" aria-label="Permalink to &quot;Step 2.3: Configure connection&quot;">​</a></h4><ol><li><p>Configure a connection between your IdP and Branch. You have two options for this:</p><ol><li>Automatic: Provide the <strong>Metadata URL</strong> to your IdP. This URL needs to be publicly accessible and ensures your IdP provides important information like login URL and certificate, OR</li><li>Manual: Configure the <strong>Single Sign-On URL</strong> and upload a <strong>Signing Certificate</strong> manually.</li></ol></li><li><p>Whether you choose automatic or manual connection configuration, you have the option to set the <strong>Advanced Settings</strong> to configure request signing if required by your IdP:</p><ol><li><p>Check the <strong>Sign Request</strong> checkbox.</p></li><li><p>When enabled, the SAML authentication request will be signed. Download the certificate and upload it to your IdP to validate the signature.</p></li><li><p>Select an option for <strong>Sign Request Algorithm</strong> (RSA-SHA256 recommended).</p></li><li><p>Select an option for <strong>Sign Request Algorithm Digest</strong> (SHA256 recommended).</p></li><li><p>Select an option for <strong>Request Protocol Binding</strong> (HTTP-Post recommended).</p><p><em>[Image: Branch settings for SAML authentication request signing and algorithm selection options displayed.]</em>.png)</p></li></ol></li><li><p>Click <strong>Create Connection</strong>. You will see an alert modal letting you know that doing this will enable SSO access to Branch.</p></li><li><p>Click <strong>Proceed.</strong></p></li></ol><h4 id="step-2-4-test-sso" tabindex="-1">Step 2.4: Test SSO <a class="header-anchor" href="#step-2-4-test-sso" aria-label="Permalink to &quot;Step 2.4: Test SSO&quot;">​</a></h4><p><strong>Note</strong>: A successful run of this test confirms that Auth0 can receive the SAML response and that your URL, audience ID, and certificate are configured correctly. However, it does not verify <a href="./configure-sso-with-auth0.html#step-23-attribute-mapping">attribute mapping</a>. After testing, review the displayed user information to confirm your IdP is passing the correct email, first name, and last name attributes.</p><ol><li>Click <strong>Test Connection</strong>. This will cause the Branch configuration page to enter “listening mode”.</li><li>In the new tab, log in using your IdP.</li><li>Return and note the “Testing complete!” confirmation message.</li><li>Important: Select <strong>Enable SSO</strong> to activate SSO. Without this step, the SSO configuration will <strong>not</strong> take effect.</li><li>You can now close the new tab.</li></ol><h2 id="email-domain-configuration" tabindex="-1">Email domain configuration <a class="header-anchor" href="#email-domain-configuration" aria-label="Permalink to &quot;Email domain configuration&quot;">​</a></h2><p>Branch&#39;s SSO uses email domains to determine which users can authenticate through your SSO connection.</p><p><strong>Existing SSO customers migrating from legacy SSO</strong></p><p>Previously configured email domains carry over from your current SSO setup.</p><div class="warning custom-block"><p class="custom-block-title">Caution</p><p>Adding a new SSO email domain: Before adding an email domain that wasn&#39;t in your legacy SSO setup, first complete the migration to Auth0 SSO. Once the Auth0 SSO setup is complete, you can add the new email domain to enable authentication for users across both domains.</p><p><strong>If this process is not followed correctly, SSO functionality may not behave as expected</strong>.</p></div><p><strong>New SSO customers (as of August 2025)</strong></p><p>Branch uses the email domain of the user setting up SSO.</p><p>If you are running into restrictions related to the list of email domains that can be configured for your setup, please contact Support at <a href="mailto:support@branch.io" target="_blank" rel="noreferrer">support@branch.io</a> (include your name and app ID) to update the values in the list.</p><h2 id="use-sso" tabindex="-1">Use SSO <a class="header-anchor" href="#use-sso" aria-label="Permalink to &quot;Use SSO&quot;">​</a></h2><p>Once your SSO connection is configured and enabled, your team can access Branch through your IdP.</p><h3 id="branch-dashboard-access" tabindex="-1">Branch Dashboard access <a class="header-anchor" href="#branch-dashboard-access" aria-label="Permalink to &quot;Branch Dashboard access&quot;">​</a></h3><p>Users with email addresses matching your configured domains will be automatically redirected to your IdP when accessing Branch at <a href="https://app.branch.io**" target="_blank" rel="noreferrer">https://app.branch.io</a>. This is the URL users should use to access Branch with SSO.</p><div class="warning custom-block"><p class="custom-block-title">Caution</p><p>As part of the Auth0 SSO migration, <strong>all vanity URLs</strong> <strong>(e.g.,</strong> <code>mycompany.dashboard.branch.io</code><strong>)</strong> <strong>will be discontinued</strong> by December 31, 2025.</p><p>Action required: Make sure you IdP configurations uses <code>https://app.branch.io</code>. Legacy vanity URLs will work temporarily during migration but will be fully retired.</p></div><p>After successful authentication, they&#39;ll be logged into Branch.</p><h3 id="user-management" tabindex="-1">User management <a class="header-anchor" href="#user-management" aria-label="Permalink to &quot;User management&quot;">​</a></h3><p>Manage users through your IdP.</p><p>Users with email addresses matching your configured domains will automatically authenticate through SSO when accessing Branch.</p><h3 id="modify-settings" tabindex="-1">Modify settings <a class="header-anchor" href="#modify-settings" aria-label="Permalink to &quot;Modify settings&quot;">​</a></h3><p>Click <strong>Configure SSO</strong> in your Branch Dashboard SSO settings to modify your SSO configuration.</p><p>Previously configured values (login URL, certificate, domains) remain populated for easy editing.</p><h3 id="connection-status" tabindex="-1">Connection status <a class="header-anchor" href="#connection-status" aria-label="Permalink to &quot;Connection status&quot;">​</a></h3><p>Your SSO configuration page displays the current connection status and configured email domains after successful setup.</p><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><p><strong>Connection issues</strong></p><ul><li>Verify your identity provider metadata URL is accessible.</li><li>If you uploaded a <a href="./configure-sso-with-auth0.html#configure-connection">signing certificate</a>, make sure it is valid and properly formatted.</li><li>Check that your <a href="./configure-sso.html#step-23-map-attributes">attribute mappings</a> match your IdP configuration.</li></ul><p><strong>User access issues</strong></p><ul><li>Confirm user email domains match your configured <a href="./configure-sso-with-auth0.html#email-domain-configuration">email domains list</a>.</li><li>Verify that users are assigned to the appropriate application in your IdP.</li><li>Check that <a href="./configure-sso.html#step-23-map-attributes">required attributes</a> are being passed.</li></ul><hr><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><details><summary>What is the purpose of using Auth0 for Branch?</summary><p>Auth0 enables single sign-on (SSO) for managing team access to the Branch Dashboard through an identity provider (IdP).</p></details><details><summary>I already have Branch SSO set up. Do I use this same guide to migrate to Auth0?</summary><p>Yes, existing Branch SSO users should follow the same steps in this guide to migrate to the new Auth0 system.</p></details><details><summary>What do I need to configure SSO for Branch?</summary><p>You need admin access to your Branch account and your organization&#39;s IdP, as well as SSO enabled for your account.</p><p>SSO requires a premium plan. Please <a href="https://branchdocs.app.link/e/sso-sign-up" target="_blank" rel="noreferrer">contact the Sales team</a> for pricing and availability.</p></details><details><summary>How can I test the SSO connection after configuration?</summary><p>You can test the connection by clicking <strong>Test Connection</strong> on the Branch configuration page and logging in using your IdP.</p></details><details><summary>What should I do if users are having access issues?</summary><p>For users having access issues, check that:</p><ul><li>User email domains match your configured <a href="./configure-sso-with-auth0.html#email-domain-configuration">email domains list</a>.</li><li>Users are assigned to the appropriate application in your IdP.</li><li><a href="./configure-sso.html#step-23-map-attributes">Required attributes</a> are being passed.</li></ul></details><details><summary>Does Branch support just-in-time/SCIM/auto account provisioning?</summary><p>Not currently. One user can belong to multiple Branch apps, so admins must decide which users on their claimed email domain should have access to which apps in Branch at this time. Admins will need to manually assign Branch accounts to individuals before they can sign in for the first time.</p></details><div class="info custom-block"><p class="custom-block-title">Note</p><p>When creating the application in your IdP, you may also need to specify an <strong>Application URL (also called SP URL)</strong>. Use <a href="https://dashboard.branch.io" target="_blank" rel="noreferrer">https://dashboard.branch.io</a> for this field.</p><p>This is the URL where users will access Branch to log in.</p></div>`,65)])])}const g=t(n,[["render",s]]);export{d as __pageData,g as default};
